#!/usr/bin/env python3
"""System Provisioning Planner - Dry-run CLI for rig configuration management."""

import argparse
import json
import os
import sys
from pathlib import Path
from typing import Any, Optional

import yaml


# ---------------------------------------------------------------------------
# Validation
# ---------------------------------------------------------------------------

class ValidationError:
    """Represents a validation error for a single config file."""
    def __init__(self, path: str, message: str):
        self.path = path
        self.message = message

    def to_dict(self) -> dict:
        return {"path": self.path, "valid": False, "errors": [self.message]}


def validate_config(content: Any, file_path: str) -> list[ValidationError]:
    """Validate a parsed config and return list of errors."""
    errors = []

    # 1. version: must be a string
    if "version" not in content:
        errors.append(ValidationError(file_path, f"'{file_path}': version required"))
        # Skip further validation if version missing
        return errors

    version = content["version"]
    if not isinstance(version, str):
        errors.append(ValidationError(file_path, f"'{file_path}': version must be a string"))
        return errors

    if version != "1":
        errors.append(ValidationError(file_path, f"'{file_path}': unsupported version '{version}'"))
        return errors

    # 2. schema required and recognized
    if "schema" not in content:
        errors.append(ValidationError(file_path, f"'{file_path}': schema required"))
        return errors

    schema = content["schema"]
    if not isinstance(schema, str):
        errors.append(ValidationError(file_path, f"'{file_path}': schema must be a string"))
        return errors

    if schema != "module":
        errors.append(ValidationError(file_path, f"'{file_path}': unsupported schema '{schema}'"))
        return errors

    # 3. os type
    if "os" in content and content["os"] is not None:
        os_val = content["os"]
        if not isinstance(os_val, dict):
            errors.append(ValidationError(file_path, f"'{file_path}': os must be an object"))
            return errors

        # 4. os.name required/type/value
        os_dict = os_val
        if "name" in os_dict:
            os_name = os_dict["name"]
            if not isinstance(os_name, str):
                errors.append(ValidationError(file_path, f"'{file_path}': os.name must be a string"))
            elif os_name not in ("macos", "linux"):
                errors.append(ValidationError(file_path, f"'{file_path}': os.name must be 'macos' or 'linux'"))
        else:
            errors.append(ValidationError(file_path, f"'{file_path}': os.name required"))

        # 5. os.package_manager type/value + requirement when packages/apps present
        if "package_manager" in os_dict:
            pm = os_dict["package_manager"]
            if not isinstance(pm, str):
                errors.append(ValidationError(file_path, f"'{file_path}': os.package_manager must be a string"))
            elif pm not in ("brew", "apt", "yum"):
                errors.append(ValidationError(file_path, f"'{file_path}': os.package_manager must be 'brew', 'apt', or 'yum'"))

        # Check requirement: if packages or applications present, package_manager required
        has_packages = "packages" in os_dict
        has_apps = "applications" in os_dict
        if (has_packages or has_apps) and "package_manager" not in os_dict:
            errors.append(ValidationError(file_path, f"'{file_path}': os.package_manager required when os.packages or os.applications present"))

        # 6. os.packages list/type/item checks
        if "packages" in os_dict:
            packages = os_dict["packages"]
            if not isinstance(packages, list):
                errors.append(ValidationError(file_path, f"'{file_path}': os.packages must be a list"))
            else:
                for i, pkg in enumerate(packages):
                    if not isinstance(pkg, str):
                        errors.append(ValidationError(file_path, f"'{file_path}': os.packages[{i}] must be a string"))
                    elif not pkg:
                        errors.append(ValidationError(file_path, f"'{file_path}': os.packages[{i}] must be a non-empty string"))

        # 7. os.applications list/type/item checks
        if "applications" in os_dict:
            apps = os_dict["applications"]
            if not isinstance(apps, list):
                errors.append(ValidationError(file_path, f"'{file_path}': os.applications must be a list"))
            else:
                for i, app in enumerate(apps):
                    if not isinstance(app, str):
                        errors.append(ValidationError(file_path, f"'{file_path}': os.applications[{i}] must be a string"))
                    elif not app:
                        errors.append(ValidationError(file_path, f"'{file_path}': os.applications[{i}] must be a non-empty string"))

    # 8. actions type and item-object checks
    if "actions" in content:
        actions = content["actions"]
        if not isinstance(actions, list):
            errors.append(ValidationError(file_path, f"'{file_path}': actions must be a list"))
        else:
            for i, action in enumerate(actions):
                if not isinstance(action, dict):
                    errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}] must be an object"))
                    continue

                # 10. actions[N].type required/type/known checks
                if "type" not in action:
                    errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].type required"))
                    type_val = None
                else:
                    type_val = action["type"]
                    if not isinstance(type_val, str):
                        errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].type must be a string"))
                    elif type_val not in ("link", "copy", "run"):
                        errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].type must be 'link', 'copy', or 'run'"))

                # 11. actions[N].source required/type/emptiness
                if "source" not in action:
                    errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].source required"))
                    source_val = None
                else:
                    source_val = action["source"]
                    if not isinstance(source_val, str):
                        errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].source must be a string"))
                    elif not source_val:
                        errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].source must be a non-empty string"))

                # 12. actions[N].destination required/type/value format and wildcard slash rule
                # Only check destination if type is link or copy
                if type_val in ("link", "copy"):
                    if "destination" not in action:
                        errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].destination required for 'link' or 'copy' type"))
                    else:
                        dest = action["destination"]
                        if not isinstance(dest, str):
                            errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].destination must be a string"))
                        elif not dest:
                            errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].destination must be a non-empty string"))
                        elif not dest.startswith(("/", "~")):
                            errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].destination must start with '/' or '~'"))

                    # Wildcard slash rule
                    if source_val == "*":
                        if "destination" not in action or not dest.endswith("/"):
                            errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].destination must end with '/' when using wildcard source"))

                # Check for non-wildcard source starting with / (invalid)
                if source_val and source_val != "*" and source_val.startswith("/"):
                    errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].source must not start with '/' for non-wildcard source"))

                # 13. actions[N].hidden and elevated type checks
                if "hidden" in action:
                    if not isinstance(action["hidden"], bool):
                        errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].hidden must be a boolean"))
                if "elevated" in action:
                    if not isinstance(action["elevated"], bool):
                        errors.append(ValidationError(file_path, f"'{file_path}': actions[{i}].elevated must be a boolean"))

    return errors


def discover_configs(dir_path: str) -> list[tuple[str, dict, Optional[ValidationError]]]:
    """Discover all rig config files in directory, returning (relative_path, parsed_content, error_if_any)."""
    results = []
    root = Path(dir_path).resolve()

    for file_path in root.rglob("*"):
        # Skip .git directories
        if ".git" in file_path.parts:
            continue

        # Check extension
        if file_path.suffix.lower() not in (".yaml", ".yml", ".json"):
            continue

        rel_path = str(file_path.relative_to(root))

        # Parse file
        try:
            with open(file_path, 'r') as f:
                # Try YAML first, then JSON
                try:
                    content = yaml.safe_load(f)
                except yaml.YAMLError as e:
                    results.append((rel_path, {}, ValidationError(rel_path, f"parse error: {e}")))
                    continue

            if content is None:
                # Empty file
                results.append((rel_path, {}, ValidationError(rel_path, "parse error: empty file")))
                continue

            # Check if it has version
            if "version" not in content:
                continue

            # Validate
            errors = validate_config(content, rel_path)
            if errors:
                results.append((rel_path, content, errors[0]))
            else:
                results.append((rel_path, content, None))

        except Exception as e:
            results.append((rel_path, {}, ValidationError(rel_path, f"parse error: {e}")))

    return sorted(results, key=lambda x: x[0])


def validate(dir_path: str) -> dict:
    """Validate all discovered rig configs and return result dict."""
    configs = discover_configs(dir_path)
    files = []
    all_valid = True

    for rel_path, content, error in configs:
        file_entry = {"path": rel_path, "valid": error is None}
        if error:
            all_valid = False
            file_entry["errors"] = [error.message]
        files.append(file_entry)

    return {"valid": all_valid, "files": files}


# ---------------------------------------------------------------------------
# Plan Generation
# ---------------------------------------------------------------------------

def resolve_destination(dest: str, home: Path) -> str:
    """Resolve ~ in destination to absolute path."""
    if dest.startswith("~"):
        return str(home / dest[1:])
    return dest


def expand_wildcard(source: str, module_dir: Path) -> list[str]:
    """Expand wildcard source to list of absolute file paths."""
    if source != "*":
        return []

    matches = []
    for item in module_dir.iterdir():
        if item.is_file() and not item.name.startswith("."):
            if item.suffix.lower() not in (".yaml", ".yml", ".json"):
                matches.append(str(item.resolve()))

    return sorted(matches)


def get_module_name(config_dir: Path, base_dir: Path) -> str:
    """Get module name relative to base directory."""
    return str(config_dir.relative_to(base_dir))


def check_duplicate_module_schemas(configs: list[tuple[str, dict, Optional[ValidationError]]]) -> list[ValidationError]:
    """Check for duplicate module schema in same directory."""
    errors = []
    dir_counts: dict[str, int] = {}

    for rel_path, content, _ in configs:
        config_path = Path(rel_path)
        dir_path = str(config_path.parent)

        # Only check if this is a module config (has schema: module)
        if content.get("schema") == "module":
            dir_counts[dir_path] = dir_counts.get(dir_path, 0) + 1

    for dir_path, count in dir_counts.items():
        if count > 1:
            errors.append(ValidationError(dir_path, f"duplicate 'module' schema in '{dir_path}'"))

    return errors


def filter_modules(
    configs: list[tuple[str, dict, Optional[ValidationError]]],
    os_filter: Optional[str] = None,
    module_filter: Optional[list[str]] = None
) -> list[tuple[str, dict]]:
    """Filter modules by OS and module name."""
    result = []

    # Group configs by directory (module)
    modules: dict[str, dict] = {}

    for rel_path, content, _ in configs:
        if content.get("schema") != "module":
            continue

        config_path = Path(rel_path)
        module_dir = str(config_path.parent)

        if module_dir not in modules:
            modules[module_dir] = {
                "name": module_dir,
                "config": content,
                "config_path": rel_path
            }

    # Apply filters
    for module_dir, module_data in modules.items():
        config = module_data["config"]

        # OS filter
        if os_filter:
            os_name = config.get("os", {}).get("name")
            if os_name is not None and os_name != os_filter:
                continue

        # Module name filter
        if module_filter:
            if module_dir not in module_filter:
                continue

        result.append((module_dir, config))

    return sorted(result, key=lambda x: x[0])


def generate_plan(
    dir_path: str,
    os_filter: Optional[str] = None,
    module_filter: Optional[list[str]] = None
) -> tuple[dict, Optional[dict]]:
    """Generate provisioning plan, returning (plan_dict, error_if_any)."""
    root_dir = Path(dir_path).resolve()
    home = Path.home()

    # Discover configs
    configs = discover_configs(dir_path)

    # Check for parse/validation errors
    validation_errors = [e for _, _, e in configs if e is not None]
    if validation_errors:
        files_output = []
        for rel_path, content, error in configs:
            file_entry = {"path": rel_path, "valid": error is None}
            if error:
                file_entry["errors"] = [error.message]
            files_output.append(file_entry)

        details = {"valid": False, "files": files_output}
        return {}, {"error": "validation_failed", "details": details}

    # Check for duplicate module schemas
    duplicate_errors = check_duplicate_module_schemas(configs)
    if duplicate_errors:
        details = {"valid": False, "files": [{"path": e.path, "valid": False, "errors": [e.message]} for e in duplicate_errors]}
        return {}, {"error": "validation_failed", "details": details}

    # Check for no configs
    module_configs = [(p, c) for p, c, _ in configs if c.get("schema") == "module"]
    if not module_configs:
        return {"modules": []}, None

    # Filter modules
    filtered_modules = filter_modules(configs, os_filter, module_filter)

    if not filtered_modules:
        return {"modules": []}, None

    # Generate plan
    plan_modules = []

    for module_dir, config in filtered_modules:
        module_path = root_dir / module_dir
        module_name = get_module_name(module_path, root_dir)

        actions = []

        # Install packages
        packages = config.get("os", {}).get("packages", [])
        package_manager = config.get("os", {}).get("package_manager", "")
        for pkg in sorted(packages):
            actions.append({
                "type": "install_package",
                "manager": package_manager,
                "package": pkg
            })

        # Install applications
        applications = config.get("os", {}).get("applications", [])
        for app in sorted(applications):
            actions.append({
                "type": "install_application",
                "manager": package_manager,
                "application": app
            })

        # Actions
        for action in config.get("actions", []):
            action_type = action["type"]
            source = action["source"]
            hidden = action.get("hidden", False)
            elevated = action.get("elevated", False)

            # Handle wildcard source
            if source == "*":
                matched_files = expand_wildcard(source, module_path)
                dest_prefix = action.get("destination", "")

                for abs_source in matched_files:
                    filename = os.path.basename(abs_source)

                    # Apply hidden modifier
                    if hidden and not filename.startswith("."):
                        filename = "." + filename

                    dest = dest_prefix + filename
                    dest = resolve_destination(dest, home)

                    actions.append({
                        "type": action_type,
                        "source": abs_source,
                        "destination": dest,
                        "elevated": elevated
                    })
            else:
                # Non-wildcard source
                # Check if file exists
                source_path = module_path / source

                if not source_path.exists():
                    # file_not_found error
                    details = {
                        "module": module_name,
                        "file": source
                    }
                    return {}, {"error": "file_not_found", "details": json.dumps(details)}

                abs_source = str(source_path.resolve())

                if action_type in ("link", "copy"):
                    dest = action["destination"]

                    # Apply hidden modifier
                    if hidden:
                        dest_filename = os.path.basename(dest)
                        if not dest_filename.startswith("."):
                            # Replace the filename part with hidden version
                            dest_dir = os.path.dirname(dest)
                            dest_filename = "." + dest_filename
                            dest = os.path.join(dest_dir, dest_filename) if dest_dir else dest_filename

                    dest = resolve_destination(dest, home)

                    actions.append({
                        "type": action_type,
                        "source": abs_source,
                        "destination": dest,
                        "elevated": elevated
                    })
                else:  # run
                    plan_action = {
                        "type": "run",
                        "source": abs_source,
                        "elevated": elevated
                    }
                    actions.append(plan_action)

        plan_modules.append({
            "name": module_name,
            "actions": actions
        })

    return {"modules": plan_modules}, None


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------

def cmd_validate(args):
    """Validate rig configs."""
    result = validate(args.dir)
    print(json.dumps(result, indent=2))
    return 0 if result["valid"] else 1


def cmd_plan(args):
    """Generate provisioning plan."""
    os_filter = args.os
    module_filter = args.module

    plan, error = generate_plan(args.dir, os_filter, module_filter)

    if error:
        print(json.dumps(error, indent=2), file=sys.stderr)
        return 1

    print(json.dumps(plan, indent=2))
    return 0


def main():
    parser = argparse.ArgumentParser(description="System Provisioning Planner")
    subparsers = parser.add_subparsers(dest="command", required=True)

    # Validate command
    validate_parser = subparsers.add_parser("validate", help="Validate rig configs")
    validate_parser.add_argument("dir", help="Directory to search for rig configs")

    # Plan command
    plan_parser = subparsers.add_parser("plan", help="Generate provisioning plan")
    plan_parser.add_argument("dir", help="Directory to search for rig configs")
    plan_parser.add_argument("--os", help="Filter by OS name (macos or linux)")
    plan_parser.add_argument("--module", nargs="*", help="Filter by module name(s)")

    args = parser.parse_args()

    if args.command == "validate":
        return cmd_validate(args)
    elif args.command == "plan":
        return cmd_plan(args)


if __name__ == "__main__":
    sys.exit(main())

