                    error_detail = json.dumps({
                        "error": "file_not_found",
                        "details": f"source file '{source}' not found"
                    })
                    print(error_detail, file=sys.stderr)
                    return 1

                # Prepare action
                abs_source = str(source_path.resolve())

                if action_type == "link":
                    dest = action["destination"]
                    if hidden:
                        # Modify destination filename to be hidden
                        dest_dir = os.path.dirname(dest)
                        dest_file = os.path.basename(dest)
                        if not dest_file.startswith("."):
                            dest_file = "." + dest_file
                        if dest_dir:
                            dest = os.path.join(dest_dir, dest_file)
                        else:
                            dest = dest_file

                    dest_abs = get_absolute_destinations(dest, home)

                    actions.append({
                        "type": "link",
                        "source": abs_source,
                        "destination": dest_abs,
                        "elevated": elevated
                    })

                elif action_type == "copy":
                    dest = action["destination"]
                    if hidden:
                        dest_dir = os.path.dirname(dest)
                        dest_file = os.path.basename(dest)
                        if not dest_file.startswith("."):
                            dest_file = "." + dest_file
                        if dest_dir:
                            dest = os.path.join(dest_dir, dest_file)
                        else:
                            dest = dest_file

                    dest_abs = get_absolute_destinations(dest, home)

                    actions.append({
                        "type": "copy",
                        "source": abs_source,
                        "destination": dest_abs,
                        "elevated": elevated
                    })

                elif action_type == "run":
                    # Run actions never emit destination even if present
                    actions.append({
                        "type": "run",
                        "source": abs_source,
                        "elevated": elevated
                    })

        # Sort actions within module
        # Packages sorted by name
        package_actions = sorted(
            [a for a in actions if a["type"] == "install_package"],
