        return 1

    root_dir = Path(args.dir).resolve()

    if args.command == "validate":
        return validate_cmd(root_dir)
    elif args.command == "plan":
        return generate_plan_cmd(root_dir, args.os, args.modules)

    return 1


if __name__ == "__main__":
    sys.exit(main())

